import type { Question } from "./questions";

type Q = Question;
const e = (exam: string, en: string, opts: string[], ans: number, exp?: string): Q => ({
  exam,
  question: { English: en, Hindi: en, Odia: en },
  options: { English: opts, Hindi: opts, Odia: opts },
  answer: ans,
  explanation: exp ? { English: exp, Hindi: exp, Odia: exp } : undefined,
});

